mapper.select:
/* com.shop.mapper.product.ProductContentList.selectProdContentList */
SELECT
      A.ID AS id
    , A.NEWS_TITLE AS newsTitle
    , A.NEWS_SUB_TITLE AS newsSubTitle
    , A.NEWS_CONTENTS AS newsContents
    , A.FILE_ID AS fileId
    , (SELECT COUNT(1) FROM TB_FILE_DET X WHERE X.FILE_ID = A.FILE_ID AND X.DEL_YN = 'N') AS imageCnt
    , (SELECT COUNT(1) FROM TB_CONTENTS_PRODUCT X WHERE X.CONTENTS_ID = A.ID AND DEL_YN = 'N') AS productCnt
FROM TB_CONTENTS A

    AND A.DEL_YN = 'N'
    AND A.NEWS_TYPE = #{filter.newsType}
    AND A.PARTNER_ID = #{filter.partnerId}

        AND A.NEWS_TITLE LIKE CONCAT('%', #{filter.newsTitle},'%')


        AND (
        A.ID > #{filter.lastId}
        )


ORDER BY A.ID
LIMIT #{pageRowCount} + 1;

mapper.update:
/* com.shop.mapper.product.ProductContentList.updateProductContents */
UPDATE TB_CONTENTS SET
      UPD_TM   = NOW()
    , UPD_USER = #{updUser}

    , NEWS_TYPE = #{newsType}


    , NEWS_TITLE = #{newsTitle}


    , NEWS_SUB_TITLE = #{newsSubTitle}


    , NEWS_CONTENTS = #{newsContents}


    , FILE_ID = #{fileId}


    , PARTNER_ID = #{partnerId}

WHERE ID = #{id}

/* com.shop.mapper.product.ProductContentList.deleteProductContents */
UPDATE TB_CONTENTS
SET DEL_YN = 'Y'
  , UPD_USER = #{updUser}
  , UPD_TM = NOW()
WHERE ID = #{id}

mapper.select:
/* com.shop.mapper.product.ProductContentList.selectProductInfoList */ SELECT TP.ID AS id , TP.PROD_CD AS prodCd , FN_GET_PARTNERNM( TP.PARTNER_ID ) AS partnerNm , TP.PROD_NM AS prodNm , TP.ORG_AMT AS orgAmt , TP.SELL_AMT AS sellAmt , FN_GET_PRODUCT_COLORS(TP.ID) AS prodColors , FN_GET_PRODUCT_SIZES(TP.ID) AS prodSizes , TP.DISCOUNT_RATE AS discountRate , TP.REP_FILE_ID AS repFileId , (SELECT COUNT(1) FROM TB_CONTENTS_PRODUCT CP WHERE CP.PRODUCT_ID = TP.ID AND CP.DEL_YN = 'N') AS contentsProductCnt FROM TB_PRODUCT TP
AND TP.DEL_YN = 'N' AND NOT EXISTS (SELECT 1 FROM TB_CONTENTS_PRODUCT CP WHERE CP.PRODUCT_ID = TP.ID AND CP.CONTENTS_ID = #{filter.contentsId})
AND TP.PROD_NM LIKE CONCAT('%', #{filter.prodNm} ,'%')
AND TP.PARTNER_ID = #{filter.partnerId}
AND ( TP.ID > #{filter.lastId} )
ORDER BY TP.PROD_NM LIMIT #{pageRowCount} + 1;

/* com.shop.mapper.product.ProductContentList.selectContentsProductInfoList */ SELECT TP.ID AS id , CP.ID AS contentsProductId , CP.SEQ AS contentsProductSeq , TP.PROD_NM AS prodNm , TP.SELL_AMT AS sellAmt , TP.REP_FILE_ID AS repFileId , FN_GET_PRODUCT_COLORS(TP.ID) AS prodColors , FN_GET_PRODUCT_SIZES(TP.ID) AS prodSizes , TP.DISCOUNT_RATE AS discountRate , FD.SYS_FILE_NM FROM TB_PRODUCT TP JOIN TB_CONTENTS_PRODUCT CP ON CP.PRODUCT_ID = TP.ID AND CP.DEL_YN = 'N' JOIN TB_FILE_DET FD ON FD.FILE_ID = TP.REP_FILE_ID AND FD.DEL_YN = 'N' AND FD.FILE_SEQ = 1
AND TP.DEL_YN = 'N' AND CP.CONTENTS_ID = #{contentsId}
GROUP BY TP.ID, CP.ID, CP.SEQ, FD.SYS_FILE_NM ORDER BY CP.SEQ

mapper.update:
/* com.shop.mapper.product.ProductContentList.updateContentsProduct */ UPDATE TB_CONTENTS_PRODUCT SET
SEQ = #{seq},
CONTENTS_ID = #{contentsId},
PRODUCT_ID = #{productId},
UPD_USER = #{updUser}, UPD_TM = NOW() WHERE ID = #{id}
